# shell/tray — system-tray icon + menu. WinForms NotifyIcon. (SPEC §4)
# ⚠️ UNVERIFIED SCAFFOLDING — written without Windows; debug on-device.
#
# New-Tray $handlers wires menu items to scriptblock callbacks:
#   @{ OnPauseResume=...; OnSkip=...; OnReset=...; OnSettings=...; OnQuit=... }

# Tray icon = the breathpause orb logo (img/breathpause-128.png) embedded as base64 so the
# single-file bundle stays dependency-free (no asset shipped alongside dist\breathpause.ps1). The
# same image drives the settings window icon + header (see New-AppIconImage). Rendered into a crisp
# 32px System.Drawing.Icon at runtime (high-quality downscale) for the notification area.
$script:AppIconPngB64 = ''
function New-TrayIcon {
    $bytes = [Convert]::FromBase64String($script:AppIconPngB64)
    $ms = New-Object System.IO.MemoryStream(, $bytes)
    $src = New-Object System.Drawing.Bitmap($ms)
    $bmp = New-Object System.Drawing.Bitmap(32, 32)
    $g = [System.Drawing.Graphics]::FromImage($bmp)
    $g.InterpolationMode = [System.Drawing.Drawing2D.InterpolationMode]::HighQualityBicubic
    $g.SmoothingMode = [System.Drawing.Drawing2D.SmoothingMode]::AntiAlias
    $g.PixelOffsetMode = [System.Drawing.Drawing2D.PixelOffsetMode]::HighQuality
    $g.Clear([System.Drawing.Color]::Transparent)
    $g.DrawImage($src, (New-Object System.Drawing.Rectangle(0, 0, 32, 32)))
    $g.Dispose(); $src.Dispose(); $ms.Dispose()
    $hicon = $bmp.GetHicon(); $bmp.Dispose()
    return [System.Drawing.Icon]::FromHandle($hicon)
}

function New-Tray {
    param([hashtable]$Handlers)
    $script:TrayHandlers = $Handlers
    $script:TrayStrings = if ($script:Strings) { $script:Strings } else { Get-DefaultStrings }
    # Seed running/paused so an early Set-TrayStrings (e.g. a preview before the first state
    # sync) relabels against a known state instead of $null.
    $script:TrayRunning = $false; $script:TrayPaused = $false
    $t = $script:TrayStrings.tray

    $ni = New-Object System.Windows.Forms.NotifyIcon
    try { $ni.Icon = New-TrayIcon } catch { $ni.Icon = [System.Drawing.SystemIcons]::Application }
    $ni.Text = 'BreathPause'
    $ni.Visible = $true

    $menu = New-Object System.Windows.Forms.ContextMenuStrip
    # Pomodoro controls (top group).
    $script:TrayStopItem = $menu.Items.Add($t.stopTimer)
    $script:TrayStopItem.add_Click({ & $script:TrayHandlers.OnStartStop })
    $script:TrayPauseItem = $menu.Items.Add($t.pause)
    $script:TrayPauseItem.add_Click({ & $script:TrayHandlers.OnPauseResume })
    $script:TraySkipItem = $menu.Items.Add($t.skip)
    $script:TraySkipItem.add_Click({ & $script:TrayHandlers.OnSkip })
    [void]$menu.Items.Add((New-Object System.Windows.Forms.ToolStripSeparator))
    # App controls (bottom group).
    $script:TraySettingsItem = $menu.Items.Add($t.settings)
    $script:TraySettingsItem.add_Click({ & $script:TrayHandlers.OnSettings })
    $script:TrayExitItem = $menu.Items.Add($t.exit)
    $script:TrayExitItem.add_Click({ & $script:TrayHandlers.OnQuit })
    $ni.ContextMenuStrip = $menu

    $script:TrayIcon = $ni
}

# Relabel menu items from a strings catalog (live preview / save). Stop/Pause keep their
# current running/paused wording via the stored state.
function Set-TrayStrings {
    param($Strings)
    $script:TrayStrings = $Strings
    $t = $Strings.tray
    if ($script:TraySkipItem) { $script:TraySkipItem.Text = $t.skip }
    if ($script:TraySettingsItem) { $script:TraySettingsItem.Text = $t.settings }
    if ($script:TrayExitItem) { $script:TrayExitItem.Text = $t.exit }
    Set-TrayRunning $script:TrayRunning
    Set-TrayPaused $script:TrayPaused
}

function Set-TrayPaused {
    param([bool]$Paused)
    $script:TrayPaused = $Paused
    $t = $script:TrayStrings.tray
    if ($script:TrayPauseItem) { $script:TrayPauseItem.Text = if ($Paused) { $t.resume } else { $t.pause } }
}

# Running -> 'Stop'; stopped (breathing-only) -> 'Start'. Pause/Skip only make sense while running.
function Set-TrayRunning {
    param([bool]$Running)
    $script:TrayRunning = $Running
    $t = $script:TrayStrings.tray
    if ($script:TrayStopItem) { $script:TrayStopItem.Text = if ($Running) { $t.stopTimer } else { $t.startTimer } }
    if ($script:TrayPauseItem) { $script:TrayPauseItem.Enabled = $Running }
}

function Set-TrayTooltip {
    param([string]$Text)
    if ($script:TrayIcon) {
        # NotifyIcon.Text is capped at 63 chars.
        $t = if ($Text.Length -gt 63) { $Text.Substring(0, 63) } else { $Text }
        $script:TrayIcon.Text = $t
    }
}

function Remove-Tray {
    if ($script:TrayIcon) { $script:TrayIcon.Visible = $false; $script:TrayIcon.Dispose() }
}
